"use client";

import { Sparkles } from "lucide-react";
import type { StockAnalysis } from "@/types";

interface StockAnalysisReportProps {
  analysis: StockAnalysis;
}

const sentimentLabels: Record<string, string> = {
  bullish: "긍정적",
  bearish: "부정적",
  neutral: "중립",
};

const sentimentStyles: Record<string, string> = {
  bullish: "bg-green-500/20 text-green-300",
  bearish: "bg-red-500/20 text-red-300",
  neutral: "bg-gray-500/20 text-gray-300",
};

/** ai_report를 섹션별로 파싱하여 카드 배열로 반환 */
function parseReportSections(aiReport: string): { title: string; content: string }[] {
  if (!aiReport?.trim()) return [];
  const sections: { title: string; content: string }[] = [];
  const parts = aiReport.split(/(?=^[📂📈🛡️📢⭐])/m).filter(Boolean);
  for (const part of parts) {
    const firstLine = part.split("\n")[0]?.trim() ?? "";
    const content = part.split("\n").slice(1).join("\n").trim();
    if (firstLine) {
      sections.push({ title: firstLine, content });
    }
  }
  if (sections.length === 0) {
    sections.push({ title: "📢 AI 분석", content: aiReport.trim() });
  }
  return sections;
}

/** "* 항목: 선택지 — 설명" 형태의 줄을 파싱하여 렌더링 */
function renderContentLine(line: string, idx: number) {
  // "* 항목: 선택지 — 설명" 패턴
  const match = line.match(/^\*\s*(.+?):\s*(.+?)\s*[—\-–]\s*(.+)$/);
  if (match) {
    return (
      <div key={idx} className="py-1.5 border-b border-white/5 last:border-0">
        <div className="flex justify-between items-baseline gap-2">
          <span className="text-gray-300 text-sm font-medium shrink-0">{match[1].trim()}</span>
          <span className="text-white text-sm font-bold text-right">{match[2].trim()}</span>
        </div>
        <p className="text-gray-500 text-xs mt-0.5">{match[3].trim()}</p>
      </div>
    );
  }

  // "* 항목: 값" 패턴 (설명 없는 경우)
  const simpleMatch = line.match(/^\*\s*(.+?):\s*(.+)$/);
  if (simpleMatch) {
    return (
      <div key={idx} className="py-1.5 border-b border-white/5 last:border-0">
        <div className="flex justify-between items-baseline gap-2">
          <span className="text-gray-300 text-sm font-medium shrink-0">{simpleMatch[1].trim()}</span>
          <span className="text-white text-sm font-bold text-right">{simpleMatch[2].trim()}</span>
        </div>
      </div>
    );
  }

  // 그 외
  if (line.trim()) {
    return <p key={idx} className="text-gray-200 text-sm py-1">{line}</p>;
  }
  return null;
}

export default function StockAnalysisReport({ analysis }: StockAnalysisReportProps) {
  const style = sentimentStyles[analysis.sentiment] ?? sentimentStyles.neutral;
  const label = sentimentLabels[analysis.sentiment] ?? "중립";
  const sections = parseReportSections(analysis.ai_report);

  return (
    <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl overflow-hidden">
      <div className="p-5 space-y-4">
        {/* 헤더 */}
        <div className="flex flex-wrap items-center gap-2">
          <Sparkles className="w-5 h-5 text-skyblue" />
          <h2 className="font-bold text-skyblue">주식콕 분석</h2>
          <span className={`text-sm font-bold px-2 py-0.5 rounded-full ${style}`}>{label}</span>
        </div>

        {/* 분석 카드 전체 표시 */}
        {sections.length > 0 ? (
          sections.map((sec, i) => (
            <div
              key={i}
              className="bg-white/5 border border-white/10 rounded-xl p-4"
            >
              <h3 className="font-bold text-skyblue mb-2 text-sm">{sec.title}</h3>
              <div>
                {sec.content.split("\n").map((line, j) => renderContentLine(line, j))}
              </div>
            </div>
          ))
        ) : (
          <div className="text-gray-200 leading-relaxed whitespace-pre-wrap text-sm">
            {analysis.ai_report}
          </div>
        )}
      </div>
    </div>
  );
}
